// File: auth_demo.dart
// Run: dart auth_demo.dart
// Note: uses SHA-256 for illustration only. Real passwords -> bcrypt/argon2.
import 'dart:convert';
import 'dart:math';
import 'package:crypto/crypto.dart';

class User { final String id, name, role; final String hash; final String salt;
  User(this.id, this.name, this.role, this.hash, this.salt); }

final users = <String, User>{};
final sessions = <String, String>{};   // sessionId -> userId
final rand = Random.secure();

String _randHex(int bytes) =>
    List.generate(bytes, (_) => rand.nextInt(256).toRadixString(16).padLeft(2,'0')).join();

String _hash(String pw, String salt) =>
    sha256.convert(utf8.encode('$salt|$pw')).toString();

void signUp(String name, String pw, String role) {
  final salt = _randHex(16);
  final u = User(_randHex(8), name, role, _hash(pw, salt), salt);
  users[u.id] = u;
  print('created user  $name  (role=$role, id=${u.id})');
}

String? login(String name, String pw) {
  final u = users.values.where((x) => x.name == name).firstOrNull;
  if (u == null) return null;
  if (_hash(pw, u.salt) != u.hash) return null;      // AUTHENTICATION
  final sid = _randHex(24);
  sessions[sid] = u.id;
  return sid;
}

bool canDeleteUser(String sessionId) {                // AUTHORIZATION
  final uid = sessions[sessionId]; if (uid == null) return false;
  final u = users[uid]!;
  return u.role == 'admin';
}

void main() {
  signUp('Ada', 'correct-horse-battery', 'user');
  signUp('Root', 'sup3r-secret', 'admin');

  print('\n-- wrong password --');
  print('login ada  wrong    -> ${login('Ada','wrong')}');

  print('\n-- right password (auth) --');
  final adaSid = login('Ada','correct-horse-battery');
  print('login ada  correct  -> $adaSid');

  print('\n-- authorization checks --');
  print('Ada  can delete users? ${canDeleteUser(adaSid!)}');
  final rootSid = login('Root','sup3r-secret');
  print('Root can delete users? ${canDeleteUser(rootSid!)}');
}

// Output:
// created user  Ada  (role=user, id=...)
// created user  Root (role=admin, id=...)
// -- wrong password --
// login ada  wrong    -> null
// -- right password (auth) --
// login ada  correct  -> a3f9b8e7...
// -- authorization checks --
// Ada  can delete users? false
// Root can delete users? true
